import { useState, useEffect, useCallback } from "react";

const API = process.env.REACT_APP_API_URL || "http://localhost:3001";

const SENTIMENT_CFG = {
  STRONG_BUY: { label: "STRONG BUY", color: "#00ff88", bg: "#00ff8812", icon: "🚀" },
  BUY:        { label: "BUY",         color: "#4ade80", bg: "#4ade8010", icon: "📈" },
  POSITIVE:   { label: "POSITIVE",    color: "#facc15", bg: "#facc1510", icon: "✨" },
  NEUTRAL:    { label: "NEUTRAL",     color: "#64748b", bg: "#64748b10", icon: "➖" },
  NEGATIVE:   { label: "NEGATIVE",    color: "#f87171", bg: "#f8717110", icon: "⚠️" },
  AVOID:      { label: "AVOID",       color: "#ef4444", bg: "#ef444412", icon: "🚫" },
};

function useFetch(url, interval = 30000) {
  const [data, setData] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);

  const fetch_ = useCallback(async () => {
    try {
      const res = await fetch(url);
      if (!res.ok) throw new Error(`HTTP ${res.status}`);
      setData(await res.json());
      setError(null);
    } catch (e) {
      setError(e.message);
    } finally {
      setLoading(false);
    }
  }, [url]);

  useEffect(() => {
    fetch_();
    const t = setInterval(fetch_, interval);
    return () => clearInterval(t);
  }, [fetch_, interval]);

  return { data, loading, error, refetch: fetch_ };
}

function Badge({ sentiment }) {
  const cfg = SENTIMENT_CFG[sentiment] || SENTIMENT_CFG.NEUTRAL;
  return (
    <span style={{
      background: cfg.bg, border: `1px solid ${cfg.color}44`,
      color: cfg.color, borderRadius: 4, padding: "2px 8px",
      fontSize: 11, fontFamily: "monospace", fontWeight: 700, letterSpacing: 1,
      whiteSpace: "nowrap",
    }}>
      {cfg.icon} {cfg.label}
    </span>
  );
}

function AppearanceCard({ appearance }) {
  const [open, setOpen] = useState(false);
  const top = appearance.topSignal;
  const cfg = top ? (SENTIMENT_CFG[top.sentiment] || SENTIMENT_CFG.NEUTRAL) : null;

  return (
    <div style={{
      background: "#ffffff", border: `1px solid ${cfg ? cfg.color + "33" : "#e2e8f0"}`,
      borderLeft: `3px solid ${cfg ? cfg.color : "#e2e8f0"}`,
      borderRadius: 10, padding: "14px 18px", marginBottom: 10, cursor: "pointer",
    }} onClick={() => setOpen(!open)}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 12 }}>
        <div style={{ flex: 1, minWidth: 0 }}>
          <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 17, color: "#0f172a", letterSpacing: 0.5, marginBottom: 4 }}>
            {appearance.title}
          </div>
          <div style={{ display: "flex", gap: 10, flexWrap: "wrap", alignItems: "center" }}>
            <span style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace" }}>{appearance.date}</span>
            <span style={{ fontSize: 11, color: "#b8c8d8", fontFamily: "monospace" }}>{appearance.source}</span>
            <span style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace" }}>
              {(appearance.textLength / 1000).toFixed(1)}k chars scanned
            </span>
          </div>
        </div>
        <div style={{ display: "flex", alignItems: "center", gap: 8, flexShrink: 0 }}>
          {appearance.signals.slice(0, 3).map((s, i) => <Badge key={i} sentiment={s.sentiment} />)}
          {appearance.signals.length > 3 && (
            <span style={{ fontSize: 11, color: "#94a3b8" }}>+{appearance.signals.length - 3}</span>
          )}
          <span style={{ color: "#94a3b8", fontSize: 12 }}>{open ? "▲" : "▼"}</span>
        </div>
      </div>

      {open && (
        <div style={{ marginTop: 14, borderTop: "1px solid #0f2744", paddingTop: 14 }}>
          {appearance.aiSummary && (
            <div style={{ background: "#f8fafc", border: "1px solid #1e3a5f", borderLeft: "3px solid #c9a227", borderRadius: 8, padding: 14, marginBottom: 14 }}>
              <div style={{ fontSize: 10, color: "#c9a227", letterSpacing: 2, fontFamily: "monospace", marginBottom: 8 }}>✦ AI ANALYSIS</div>
              <div style={{ fontSize: 12, color: "#64748b", lineHeight: 1.7, whiteSpace: "pre-wrap" }}>{appearance.aiSummary}</div>
            </div>
          )}
          {appearance.signals.map((sig, i) => {
            const scfg = SENTIMENT_CFG[sig.sentiment] || SENTIMENT_CFG.NEUTRAL;
            return (
              <div key={i} style={{ marginBottom: 10, background: scfg.bg, border: `1px solid ${scfg.color}22`, borderRadius: 8, padding: "10px 12px" }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
                  <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
                    <span style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 16, color: scfg.color, letterSpacing: 1 }}>{sig.company}</span>
                    <Badge sentiment={sig.sentiment} />
                  </div>
                  <span style={{ color: scfg.color, fontFamily: "monospace", fontSize: 13, fontWeight: 700 }}>
                    {sig.score > 0 ? "+" : ""}{sig.score}
                  </span>
                </div>
                {sig.hits.map((hit, j) => (
                  <div key={j} style={{ fontSize: 12, color: "#64748b", fontStyle: "italic", marginTop: 4 }}>"{hit.quote}"</div>
                ))}
              </div>
            );
          })}
          {appearance.url && (
            <a href={appearance.url} target="_blank" rel="noreferrer"
              style={{ fontSize: 11, color: "#b8c8d8", fontFamily: "monospace", textDecoration: "none" }}
              onClick={e => e.stopPropagation()}>
              🔗 View original transcript →
            </a>
          )}
        </div>
      )}
    </div>
  );
}

// ── Daily Digest Row ──────────────────────────────────────────────────────────
function DigestRow({ entry, rank }) {
  const isUp = entry.direction === "up";
  const isDown = entry.direction === "down";
  const noData = entry.pctChange === null;

  const pctColor = noData ? "#334155" : isUp ? "#00ff88" : "#ef4444";
  const pctBg = noData ? "transparent" : isUp ? "#00ff8812" : "#ef444412";
  const arrow = noData ? "–" : isUp ? "▲" : "▼";

  return (
    <div style={{
      display: "grid",
      gridTemplateColumns: "36px 140px 80px 120px 120px 130px 1fr",
      alignItems: "center",
      gap: 0,
      padding: "13px 20px",
      borderBottom: "1px solid #0d1520",
      background: rank % 2 === 0 ? "#f8fafc" : "#f1f5f9",
      transition: "background 0.15s",
    }}
      onMouseEnter={e => e.currentTarget.style.background = "#e8edf5"}
      onMouseLeave={e => e.currentTarget.style.background = rank % 2 === 0 ? "#f8fafc" : "#f1f5f9"}
    >
      {/* Rank */}
      <div style={{ fontSize: 12, color: "#b8c8d8", fontFamily: "monospace", textAlign: "center" }}>
        {rank}
      </div>

      {/* Company + Ticker */}
      <div>
        <div style={{ fontFamily: "'Bebas Neue', sans-serif", fontSize: 17, color: "#0f172a", letterSpacing: 1 }}>
          {entry.company}
        </div>
        <div style={{ fontSize: 10, color: "#94a3b8", fontFamily: "monospace" }}>{entry.ticker}</div>
      </div>

      {/* First mention date */}
      <div style={{ fontSize: 11, color: "#64748b", fontFamily: "monospace" }}>
        {entry.firstMentionDate}
      </div>

      {/* First mention price */}
      <div style={{ fontFamily: "monospace", fontSize: 14 }}>
        {entry.firstMentionPrice !== null
          ? <span style={{ color: "#64748b" }}>${entry.firstMentionPrice.toFixed(2)}</span>
          : <span style={{ color: "#b8c8d8" }}>N/A</span>
        }
      </div>

      {/* Current price */}
      <div style={{ fontFamily: "monospace", fontSize: 14 }}>
        {entry.currentPrice !== null
          ? <span style={{ color: "#1e293b" }}>${entry.currentPrice.toFixed(2)}</span>
          : <span style={{ color: "#b8c8d8" }}>N/A</span>
        }
      </div>

      {/* % Change — green/red pill */}
      <div>
        <span style={{
          background: pctBg,
          color: pctColor,
          border: `1px solid ${pctColor}33`,
          borderRadius: 6,
          padding: "3px 10px",
          fontFamily: "monospace",
          fontSize: 14,
          fontWeight: 700,
        }}>
          {noData ? "–" : `${arrow} ${Math.abs(entry.pctChange).toFixed(2)}%`}
        </span>
      </div>

      {/* Speech */}
      <div style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace", overflow: "hidden", textOverflow: "ellipsis", whiteSpace: "nowrap", paddingLeft: 12 }}>
        {entry.firstMentionSpeech}
      </div>
    </div>
  );
}

function Tab({ id, label, active, onClick, disabled }) {
  return (
    <button onClick={() => !disabled && onClick(id)} style={{
      padding: "8px 18px", borderRadius: 7, fontSize: 13, border: "none",
      fontFamily: "system-ui, sans-serif", fontWeight: 500,
      background: active ? "#c9a227" : "transparent",
      color: disabled ? "#b8c8d8" : active ? "#0f172a" : "#475569",
      cursor: disabled ? "not-allowed" : "pointer", transition: "all 0.15s",
    }}>{label}</button>
  );
}

export default function App() {
  const [activeTab, setActiveTab] = useState("live");
  const [manualText, setManualText] = useState("");
  const [manualTitle, setManualTitle] = useState("");
  const [manualDate, setManualDate] = useState("");
  const [scanning, setScanning] = useState(false);
  const [scanResult, setScanResult] = useState(null);
  const [triggering, setTriggering] = useState(false);
  const [digestLoading, setDigestLoading] = useState(false);
  const [digestData, setDigestData] = useState(null);

  const { data: status, refetch: refetchStatus } = useFetch(`${API}/api/status`, 15000);
  const { data: appearances, loading: appLoading, refetch: refetchApps } = useFetch(`${API}/api/appearances?limit=50`, 20000);
  const { data: signals } = useFetch(`${API}/api/signals?limit=100`, 20000);
  const { data: companies } = useFetch(`${API}/api/companies`, 30000);

  const buySignals = (signals || []).filter(s => s.sentiment === "STRONG_BUY" || s.sentiment === "BUY");
  const avoidSignals = (signals || []).filter(s => s.sentiment === "AVOID" || s.sentiment === "NEGATIVE");

  async function loadDigest() {
    setDigestLoading(true);
    try {
      const res = await fetch(`${API}/api/digest`);
      const data = await res.json();
      setDigestData(data);
    } catch (e) {
      setDigestData({ error: e.message });
    } finally {
      setDigestLoading(false);
    }
  }

  // Load digest when tab is opened
  useEffect(() => {
    if (activeTab === "digest") loadDigest();
  }, [activeTab]);

  async function triggerPoll() {
    setTriggering(true);
    try {
      await fetch(`${API}/api/poll`, { method: "POST" });
      setTimeout(() => { refetchStatus(); refetchApps(); setTriggering(false); }, 3000);
    } catch { setTriggering(false); }
  }

  async function submitManualScan() {
    if (!manualText.trim() || scanning) return;
    setScanning(true);
    setScanResult(null);
    try {
      const res = await fetch(`${API}/api/scan`, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ title: manualTitle, date: manualDate, text: manualText }),
      });
      const data = await res.json();
      setScanResult(data);
      refetchApps();
    } catch (e) {
      setScanResult({ error: e.message });
    } finally {
      setScanning(false);
    }
  }

  const serverOnline = !!status;

  return (
    <>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Bebas+Neue&display=swap');
        * { box-sizing: border-box; margin: 0; padding: 0; }
        body { background: #f1f5f9; color: #1e293b; font-family: system-ui, sans-serif; }
        ::-webkit-scrollbar { width: 4px; }
        ::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 2px; }
        textarea, input { color-scheme: light; }
        @keyframes pulse { 0%,100%{opacity:1}50%{opacity:.3} }
        @keyframes fadein { from{opacity:0;transform:translateY(10px)}to{opacity:1;transform:translateY(0)} }
        .fadein { animation: fadein .3s ease both; }
      `}</style>

      <div style={{ minHeight: "100vh", background: "#f1f5f9" }}>
        {/* ── Header ── */}
        <div style={{ background: "#ffffff", borderBottom: "1px solid #0f2744", padding: "18px 32px" }}>
          <div style={{ maxWidth: 1300, margin: "0 auto", display: "flex", alignItems: "center", justifyContent: "space-between", flexWrap: "wrap", gap: 12 }}>
            <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
              <div style={{ width: 40, height: 40, borderRadius: 8, background: "linear-gradient(135deg,#b22234,#7a1520)", display: "flex", alignItems: "center", justifyContent: "center", fontSize: 20 }}>🎙️</div>
              <div>
                <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 24, letterSpacing: 2, color: "#0f172a" }}>TRUMP SIGNAL TRACKER</div>
                <div style={{ fontSize: 10, color: "#94a3b8", letterSpacing: 1.5, fontFamily: "monospace" }}>LIVE TRANSCRIPT MONITOR · AUTO-POLLING · AI ANALYSIS · STOCK TRACKER</div>
              </div>
            </div>
            <div style={{ display: "flex", alignItems: "center", gap: 20, flexWrap: "wrap" }}>
              {status && (
                <>
                  <Stat label="APPEARANCES" value={status.appearancesTracked} color="#c9a227" />
                  <Stat label="BUY SIGNALS" value={buySignals.length} color="#00ff88" />
                  <Stat label="AVOID" value={avoidSignals.length} color="#ef4444" />
                  <Stat label="POLLS RUN" value={status.pollCount} color="#64748b" />
                </>
              )}
              <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                <div style={{ width: 7, height: 7, borderRadius: "50%", background: serverOnline ? "#00ff88" : "#ef4444", animation: "pulse 2s infinite" }} />
                <span style={{ fontSize: 11, color: serverOnline ? "#00ff88" : "#ef4444", fontFamily: "monospace" }}>
                  {serverOnline ? "SERVER ONLINE" : "SERVER OFFLINE"}
                </span>
              </div>
              <button onClick={triggerPoll} disabled={triggering} style={{
                padding: "7px 16px", borderRadius: 6, border: "1px solid #1e3a5f",
                background: triggering ? "#b8c8d8" : "#f0f4f8", color: triggering ? "#334155" : "#64748b",
                fontSize: 12, cursor: triggering ? "not-allowed" : "pointer", fontFamily: "monospace",
              }}>
                {triggering ? "⏳ Polling..." : "⚡ Poll Now"}
              </button>
            </div>
          </div>
        </div>

        <div style={{ maxWidth: 1300, margin: "0 auto", padding: "24px 32px" }}>
          {!serverOnline && !appLoading && (
            <div style={{ background: "#fff5f5", border: "1px solid #ef444433", borderRadius: 10, padding: "16px 20px", marginBottom: 20 }}>
              <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 18, color: "#ef4444", letterSpacing: 1, marginBottom: 6 }}>⚠ SERVER NOT RUNNING</div>
              <div style={{ fontSize: 13, color: "#64748b", lineHeight: 1.7 }}>
                Start the backend:<br/>
                <code style={{ fontFamily: "monospace", color: "#c9a227" }}>cd server && npm install && cp .env.example .env && node index.js</code>
              </div>
            </div>
          )}

          {/* ── Tabs ── */}
          <div style={{ display: "flex", gap: 4, marginBottom: 24, background: "#ffffff", borderRadius: 10, padding: 4, border: "1px solid #0f2744", width: "fit-content" }}>
            {[
              { id: "live",     label: "📡 Live Feed" },
              { id: "digest",   label: "📈 Daily Digest" },
              { id: "signals",  label: "📊 Signal Board" },
              { id: "companies",label: "🏢 Companies" },
              { id: "manual",   label: "📝 Manual Scan" },
            ].map(t => <Tab key={t.id} {...t} active={activeTab === t.id} onClick={setActiveTab} />)}
          </div>

          {/* ── LIVE FEED ── */}
          {activeTab === "live" && (
            <div className="fadein">
              <div style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace", letterSpacing: 1, marginBottom: 16 }}>
                {(appearances || []).length} APPEARANCES TRACKED · AUTO-REFRESHES EVERY 20s
                {status?.lastPoll && <> · LAST POLL: {new Date(status.lastPoll).toLocaleTimeString()}</>}
              </div>
              {appLoading && <div style={{ color: "#94a3b8", fontFamily: "monospace", fontSize: 13 }}>Loading appearances...</div>}
              {(appearances || []).map(a => <AppearanceCard key={a.id} appearance={a} />)}
              {!appLoading && (appearances || []).length === 0 && (
                <div style={{ color: "#94a3b8", textAlign: "center", padding: "60px 0" }}>
                  <div style={{ fontSize: 32, marginBottom: 12 }}>📡</div>
                  <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 20, letterSpacing: 2 }}>WAITING FOR TRANSCRIPTS</div>
                </div>
              )}
            </div>
          )}

          {/* ── DAILY DIGEST ── */}
          {activeTab === "digest" && (
            <div className="fadein">
              <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 20 }}>
                <div>
                  <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 22, letterSpacing: 2, color: "#0f172a" }}>
                    DAILY STOCK DIGEST
                  </div>
                  <div style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace", marginTop: 4 }}>
                    Companies Trump has mentioned · First-mention price vs current price · Yahoo Finance data
                    {digestData?.generatedAt && <> · Updated {new Date(digestData.generatedAt).toLocaleTimeString()}</>}
                  </div>
                </div>
                <button onClick={loadDigest} disabled={digestLoading} style={{
                  padding: "8px 18px", borderRadius: 7, border: "1px solid #1e3a5f",
                  background: "#ffffff", color: digestLoading ? "#334155" : "#c9a227",
                  fontSize: 12, cursor: digestLoading ? "not-allowed" : "pointer", fontFamily: "monospace",
                }}>
                  {digestLoading ? "⏳ Refreshing..." : "🔄 Refresh Prices"}
                </button>
              </div>

              {digestLoading && (
                <div style={{ color: "#94a3b8", fontFamily: "monospace", fontSize: 13, padding: "40px 0", textAlign: "center" }}>
                  Fetching live prices from Yahoo Finance...
                </div>
              )}

              {digestData?.error && (
                <div style={{ color: "#ef4444", fontFamily: "monospace", fontSize: 13 }}>Error: {digestData.error}</div>
              )}

              {digestData?.entries && digestData.entries.length === 0 && (
                <div style={{ color: "#94a3b8", textAlign: "center", padding: "60px 0" }}>
                  <div style={{ fontSize: 32, marginBottom: 12 }}>📈</div>
                  <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 18, letterSpacing: 2 }}>NO COMPANY MENTIONS YET</div>
                  <div style={{ fontSize: 12, marginTop: 6 }}>Prices will appear here once Trump mentions companies in scanned speeches</div>
                </div>
              )}

              {digestData?.entries && digestData.entries.length > 0 && (
                <div style={{ background: "#ffffff", border: "1px solid #0f2744", borderRadius: 12, overflow: "hidden" }}>
                  {/* Table header */}
                  <div style={{
                    display: "grid",
                    gridTemplateColumns: "36px 140px 80px 120px 120px 130px 1fr",
                    gap: 0,
                    padding: "10px 20px",
                    background: "#f8fafc",
                    borderBottom: "1px solid #0f2744",
                  }}>
                    {["#", "COMPANY", "FIRST SEEN", "PRICE THEN", "PRICE NOW", "CHANGE", "SPEECH"].map((h, i) => (
                      <div key={i} style={{ fontSize: 10, color: "#94a3b8", fontFamily: "monospace", letterSpacing: 1.5, paddingLeft: i === 6 ? 12 : 0 }}>{h}</div>
                    ))}
                  </div>

                  {/* Table rows */}
                  {digestData.entries.map((entry, i) => (
                    <DigestRow key={entry.company} entry={entry} rank={i + 1} />
                  ))}

                  {/* Legend */}
                  <div style={{ padding: "12px 20px", borderTop: "1px solid #0d1520", display: "flex", gap: 20, alignItems: "center" }}>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <span style={{ color: "#00ff88", fontSize: 12, fontFamily: "monospace" }}>▲ GREEN</span>
                      <span style={{ fontSize: 11, color: "#94a3b8" }}>= stock up since Trump first mentioned it</span>
                    </div>
                    <div style={{ display: "flex", alignItems: "center", gap: 6 }}>
                      <span style={{ color: "#ef4444", fontSize: 12, fontFamily: "monospace" }}>▼ RED</span>
                      <span style={{ fontSize: 11, color: "#94a3b8" }}>= stock down since first mention</span>
                    </div>
                    <div style={{ fontSize: 11, color: "#b8c8d8", marginLeft: "auto" }}>
                      Prices delayed 15–20 min · Not financial advice
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}

          {/* ── SIGNAL BOARD ── */}
          {activeTab === "signals" && (
            <div className="fadein" style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 24 }}>
              <div>
                <SectionHead color="#00ff88">🚀 BUY SIGNALS</SectionHead>
                {buySignals.length === 0 && <Empty>No buy signals detected yet</Empty>}
                {buySignals.map((s, i) => <SignalRow key={i} signal={s} />)}
              </div>
              <div>
                <SectionHead color="#ef4444">🚫 AVOID SIGNALS</SectionHead>
                {avoidSignals.length === 0 && <Empty>No avoid signals detected yet</Empty>}
                {avoidSignals.map((s, i) => <SignalRow key={i} signal={s} />)}
              </div>
            </div>
          )}

          {/* ── COMPANIES ── */}
          {activeTab === "companies" && (
            <div className="fadein">
              <SectionHead color="#c9a227">🏢 COMPANY LEADERBOARD — Cumulative Signal Score</SectionHead>
              {(companies || []).length === 0 && <Empty>No company data yet</Empty>}
              <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fill,minmax(260px,1fr))", gap: 12, marginTop: 16 }}>
                {(companies || []).map((c, i) => {
                  const cfg = SENTIMENT_CFG[c.latestSentiment] || SENTIMENT_CFG.NEUTRAL;
                  return (
                    <div key={i} style={{ background: "#ffffff", border: `1px solid ${cfg.color}33`, borderLeft: `3px solid ${cfg.color}`, borderRadius: 10, padding: "14px 16px" }}>
                      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", marginBottom: 6 }}>
                        <span style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 18, color: "#0f172a", letterSpacing: 1 }}>{c.company}</span>
                        <span style={{ color: cfg.color, fontFamily: "monospace", fontSize: 16, fontWeight: 700 }}>{c.totalScore > 0 ? "+" : ""}{c.totalScore}</span>
                      </div>
                      <div style={{ display: "flex", gap: 8, alignItems: "center" }}>
                        <Badge sentiment={c.latestSentiment} />
                        <span style={{ fontSize: 11, color: "#94a3b8", fontFamily: "monospace" }}>{c.signalCount} signal{c.signalCount !== 1 ? "s" : ""}</span>
                      </div>
                      <div style={{ fontSize: 11, color: "#b8c8d8", marginTop: 6, fontFamily: "monospace" }}>
                        {c.appearances.slice(0, 2).join(" · ")}
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          )}

          {/* ── MANUAL SCAN ── */}
          {activeTab === "manual" && (
            <div className="fadein" style={{ maxWidth: 800 }}>
              <div style={{ fontSize: 13, color: "#64748b", lineHeight: 1.7, marginBottom: 20 }}>
                Paste any Trump transcript directly. The server scans it, adds it to the tracker, and records the stock price at time of mention for the Daily Digest.
              </div>
              <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12, marginBottom: 12 }}>
                <Field label="TITLE" value={manualTitle} onChange={setManualTitle} placeholder="e.g. Rally in Phoenix" />
                <Field label="DATE" value={manualDate} onChange={setManualDate} type="date" />
              </div>
              <textarea
                value={manualText}
                onChange={e => setManualText(e.target.value)}
                placeholder="Paste transcript text here..."
                style={{ width: "100%", minHeight: 220, background: "#ffffff", border: "1px solid #0f2744", borderRadius: 10, padding: 16, color: "#1e293b", fontSize: 14, outline: "none", resize: "vertical", lineHeight: 1.7, marginBottom: 12 }}
              />
              <button onClick={submitManualScan} disabled={scanning || !manualText.trim()} style={{
                width: "100%", padding: 15, borderRadius: 10, border: "none",
                background: scanning || !manualText.trim() ? "#b8c8d8" : "linear-gradient(135deg,#b22234,#8b1a27,#c9a227)",
                color: scanning || !manualText.trim() ? "#334155" : "#fff",
                fontSize: 14, fontFamily: "'Bebas Neue',sans-serif", letterSpacing: 3,
                cursor: scanning || !manualText.trim() ? "not-allowed" : "pointer",
              }}>
                {scanning ? "⚡ SCANNING..." : "🔍 SCAN FOR SIGNALS"}
              </button>
              {scanResult && !scanResult.error && (
                <div style={{ marginTop: 20 }}>
                  <AppearanceCard appearance={scanResult} />
                  {scanResult.hasSignals && (
                    <div style={{ marginTop: 10, fontSize: 12, color: "#c9a227", fontFamily: "monospace" }}>
                      ✦ Stock prices recorded — check the Daily Digest tab
                    </div>
                  )}
                </div>
              )}
              {scanResult?.error && (
                <div style={{ marginTop: 12, color: "#ef4444", fontSize: 13, fontFamily: "monospace" }}>Error: {scanResult.error}</div>
              )}
            </div>
          )}
        </div>

        <div style={{ borderTop: "1px solid #0d1117", padding: "14px 32px", marginTop: 20 }}>
          <div style={{ maxWidth: 1300, margin: "0 auto", display: "flex", justifyContent: "space-between" }}>
            <span style={{ fontSize: 10, color: "#b8c8d8", fontFamily: "monospace" }}>FOR INFORMATIONAL USE ONLY · NOT FINANCIAL ADVICE</span>
            <span style={{ fontSize: 10, color: "#b8c8d8", fontFamily: "monospace" }}>Sources: Rev.com · Factbase · Yahoo Finance · Claude AI</span>
          </div>
        </div>
      </div>
    </>
  );
}

function Stat({ label, value, color }) {
  return (
    <div style={{ textAlign: "center" }}>
      <div style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 22, color }}>{value ?? "–"}</div>
      <div style={{ fontSize: 10, color: "#94a3b8", letterSpacing: 1, fontFamily: "monospace" }}>{label}</div>
    </div>
  );
}

function SectionHead({ color, children }) {
  return <div style={{ fontSize: 11, color, letterSpacing: 2, fontFamily: "monospace", marginBottom: 12 }}>{children}</div>;
}

function Empty({ children }) {
  return <div style={{ color: "#b8c8d8", fontSize: 13, fontFamily: "monospace", padding: "20px 0" }}>{children}</div>;
}

function SignalRow({ signal }) {
  const cfg = SENTIMENT_CFG[signal.sentiment] || SENTIMENT_CFG.NEUTRAL;
  return (
    <div style={{ background: "#ffffff", border: `1px solid ${cfg.color}22`, borderLeft: `3px solid ${cfg.color}`, borderRadius: 8, padding: "10px 14px", marginBottom: 8 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center" }}>
        <div>
          <span style={{ fontFamily: "'Bebas Neue',sans-serif", fontSize: 17, color: "#0f172a", letterSpacing: 1 }}>{signal.company}</span>
          <div style={{ fontSize: 10, color: "#94a3b8", fontFamily: "monospace", marginTop: 2 }}>{signal.date} · {signal.appearanceTitle}</div>
        </div>
        <span style={{ color: cfg.color, fontFamily: "monospace", fontSize: 14, fontWeight: 700 }}>{signal.score > 0 ? "+" : ""}{signal.score}</span>
      </div>
    </div>
  );
}

function Field({ label, value, onChange, placeholder, type = "text" }) {
  return (
    <div>
      <label style={{ fontSize: 11, color: "#64748b", letterSpacing: 1, fontFamily: "monospace", display: "block", marginBottom: 6 }}>{label}</label>
      <input
        type={type} value={value} onChange={e => onChange(e.target.value)} placeholder={placeholder}
        style={{ width: "100%", background: "#ffffff", border: "1px solid #0f2744", borderRadius: 8, padding: "10px 14px", color: "#1e293b", fontSize: 14, outline: "none" }}
      />
    </div>
  );
}
